var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"후후후, 이제 아무도 저를 막을 수 없는 것이에요!","JPN":"ふふふ、もう誰にも私を止められないのです！","ENG":"*Chuckle* No one can stop me now. No one!","TWN":"哈哈哈，現在再也沒有人可以阻止我了！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"이 선택 받은 힘으로 앞으로 영원히 따돌림 따위는 없는 학교를 만들겠다, 이 말인 것이에요!","JPN":"この選ばれし力で永遠にいじめのない学校を作る、ということなのです！","ENG":"By me, the blessed one, this school will be free of bullies forever!","TWN":"用這個被選中的力量，我要創造一個永遠沒有霸凌的學校，沒錯！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"그러니까 당장! 내 점심식사에 장난질을 한 두 사람을 어서 내 앞에 대령하는 것이에요!!","JPN":"だから今すぐ！　私の給食にいたずらをした二人を私の前に連れてくるのです！！","ENG":"So go on now! Go and bring the two that spoiled my lunch!","TWN":"所以立刻！把那兩個在我午餐裡惡作劇的人帶到我面前來！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"그렇지 않으면 이 학교를 모조리......!","JPN":"そうしないと、この学校を丸ごと……","ENG":"Otherwise, I'm going to destroy the entire schoo—","TWN":"不然的話，我就把這所學校全部……！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"아, 아니 모조리는 좀 그렇고......","JPN":"い、いや、丸ごとは行き過ぎで……","ENG":"N-no, that sounds too harsh.","TWN":"不，全部的話好像有點過頭了……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"신축중인 매점 건물을 불태워 버릴 것이에요!!!","JPN":"新築工事中の売店を燃やしてしまうのです！！！","ENG":"I'm going to burn down that new school cafeteria they're building!","TWN":"我就把新建中的合作社燒掉！！！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AP_EXTRA_POLICE_NULL","text":{"KOREA":"대장님!","JPN":"隊長！","ENG":"Captain!","TWN":"隊長！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"어때? 알아봤어? 저 카운터 학생, 능력이 정확히 뭐래?","JPN":"どうだ？　調べてみたか？　あのカウンター、正確な能力は何だって？","ENG":"So? What is it? What kind of powers does that student Counter have?","TWN":"怎麼？確認過了嗎？那個制裁者學生的能力究竟是什麼？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AP_EXTRA_POLICE_NULL","text":{"KOREA":"아, 그게...... 아쉽게도 관련자료가 아무것도 없다고 합니다. ","JPN":"あ、それが……残念ながら、関連資料が何もないそうです。","ENG":"Oh, well... I'm afraid they don't have any data about her.","TWN":"啊，那個……很遺憾，沒有任何的相關資料。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AP_EXTRA_POLICE_NULL","text":{"KOREA":"이번에도 아마 정식 카운터가 아니라 <color=#ffd34c>엘릭서</color> 복용자인 모양입니다.","JPN":"たぶん今回も、正式カウンターではなく<color=#ffd34c>エリクサー</color>の服用者だと思います。","ENG":"I assume she's an <color=#ffd34c>Elixir</color> taker, not a real Counter.","TWN":"這次恐怕也不是正式制裁者，而是服用了<color=#ffd34c>聖水</color>的人。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"......또야?","JPN":"……またか。","ENG":"Again?","TWN":"……又來了？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"이번 달에만 세 번째 아닌가 이거? 정말 머리 아프구만.","JPN":"今月だけで3回目だぞ？　ったく頭が痛いな。","ENG":"Isn't this the third time just this month? This is starting to give me a migraine.","TWN":"光是這個月，這已經是第三起了吧？真是頭痛啊。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"AP_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"모, 못 들었나요? 매점을 태워버린다니까요?!","JPN":"き、聞こえてないんですか？　売店が燃やされるんですよ！？","ENG":"D-do you hear me? I'm going to burn down the school cafeteria!","TWN":"喂，你們沒聽到嗎？我說我要把合作社燒掉喔？！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"당장 두 사람을 데려와서 사과시키지 않으면 다시는 매점을 이용할 수 없는 것이에요!","JPN":"今すぐあの二人を連れてきて謝罪させないと、\\n二度と売店を利用できなくなるのです！","ENG":"Unless you bring those two and make them apologize, nobody gets to use the cafeteria again!","TWN":"馬上把那兩個人帶到我面前，向我道歉，不然你們就別想再去合作社買東西了！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"그런데, 아까부터 누굴 데려오라는 거야?","JPN":"ところで、さっきから誰を連れてこいと言ってるんだ？","ENG":"So... Who are we supposed to bring?","TWN":"呃，她從剛才開始就說要把誰帶過去？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"학생은 알아?","JPN":"君は知ってるか？","ENG":"Any idea, kid?","TWN":"同學你知道嗎？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"펴, 평소에 저 애를 자주 괴롭히던 불량 학생들인데요.","JPN":"ふ、普段からあの子をいじめていた不良生徒のことです。","ENG":"Sh-she's talking about those bullies who have been picking on her at school.","TWN":"是、是平時經常欺負她的不良學生們。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};